{"code": "
import urllib.request, json

# Fetch developer/indie hacking trends from Hacker News
try:
    with urllib.request.urlopen('https://hn.algolia.com/api/v1/search?query=AI%20OR%20startup%20OR%20indie%20hacking&tags=story&hitsPerPage=8', timeout=10) as r:
        hn = json.loads(r.read().decode())
    print("=== HACKER NEWS ===")
    for i, hit in enumerate(hn.get('hits', [])[:8]):
        title = hit.get('title', '')
        url = hit.get('url', '')
        points = hit.get('points', 0)
        if title:
            print(f"{i+1}. {title} ({points} pts)")
            if url:
                print(f"   {url}")
except Exception as e:
    print(f"HN error: {e}")
"}

